sql:
SELECT servers.name AS Server_Name, server_admins.username AS Admin_Name
FROM servers
INNER JOIN server_admins ON servers.server_id = server_admins.server_id;

SELECT admin_id, username, email, role, registered_since, last_login
FROM server_admins
WHERE server_id = 1;

external_knowledge:
- "digital giants" refers to servers;
- "awake" means servers with a status of 'Online';
- "sweating under heavy computational loads" refers to servers with CPU usage greater than 50%.

sql:
SELECT server_id, COUNT(*) AS num_players
FROM player_servers
GROUP BY server_id;

SELECT AVG(duration) 
FROM player_activity 
WHERE player_id = 1;

SELECT name, game_mode, current_players, status
FROM servers
WHERE game_mode = 'PvP' AND current_players > 0;

SELECT AVG(duration) AS average_session_duration
FROM player_activity
WHERE server_id = (SELECT server_id FROM servers WHERE name = '[us] vukland pverp livemap');

SELECT pa.activity_type, s.name 
FROM player_activity pa
JOIN servers s ON pa.server_id = s.server_id;

SELECT servers.name, server_updates.update_time
FROM servers
INNER JOIN server_updates ON servers.server_id = server_updates.server_id;
